using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(TicketClassifierService classifierService) : ControllerBase
{
    [HttpPost("train")]
    public ActionResult<TrainingResult> Train()
    {
        var result = classifierService.Train();
        return Ok(result);
    }

    [HttpPost("predict")]
    public ActionResult<PredictionResult> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        if (!classifierService.IsModelTrained)
            return BadRequest("Model has not been trained. Call POST /api/ticket-classifier/train first.");

        var result = classifierService.Predict(request);
        return Ok(result);
    }
}

