1. using Microsoft.ML;
2. using TicketClassifier.Models;
3. 
4. namespace TicketClassifier.Services;
5. 
6. public class TicketClassifierService
7. {
8.     private readonly MLContext _mlContext;
9.     private readonly string _dataPath;
10.     private ITransformer? _model;
11.     private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
12.     private string[] _categoryNames = [];
13.     private readonly Lock _lock = new();
14. 
15.     public bool IsModelTrained => _model is not null;
16. 
17.     public TicketClassifierService(IWebHostEnvironment env)
18.     {
19.         _mlContext = new MLContext(seed: 42);
20.         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
21.     }
22. 
23.     public TrainingResult Train()
24.     {
25.         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
26.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
27. 
28.         // Capture category names for mapping scores to labels
29.         var categories = _mlContext.Data
30.             .CreateEnumerable<TicketData>(dataView, reuseRowObject: false)
31.             .Select(t => t.Category)
32.             .Distinct()
33.             .OrderBy(c => c)
34.             .ToArray();
35. 
36.         var pipeline = _mlContext.Transforms.Text
37.             .FeaturizeText("SubjectFeatures", nameof(TicketData.Subject))
38.             .Append(_mlContext.Transforms.Text
39.                 .FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
40.             .Append(_mlContext.Transforms.Concatenate("Features",
41.                 "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
42.             .Append(_mlContext.Transforms.Conversion
43.                 .MapValueToKey("Label"))
44.             .Append(_mlContext.MulticlassClassification.Trainers
45.                 .SdcaMaximumEntropy("Label", "Features"))
46.             .Append(_mlContext.Transforms.Conversion
47.                 .MapKeyToValue("PredictedLabel"));
48. 
49.         // Cross-validate to get metrics on the small dataset
50.         var cvResults = _mlContext.MulticlassClassification
51.             .CrossValidate(dataView, pipeline, numberOfFolds: 3);
52. 
53.         // Train the final model on all data
54.         var model = pipeline.Fit(dataView);
55. 
56.         lock (_lock)
57.         {
58.             _model = model;
59.             _categoryNames = categories;
60.             _predictionEngine = _mlContext.Model
61.                 .CreatePredictionEngine<TicketData, TicketPrediction>(model);
62.         }
63. 
64.         var best = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
65.         var metrics = best.Metrics;
66. 
67.         var perCategory = new List<CategoryMetric>();
68.         for (var i = 0; i < metrics.PerClassLogLoss.Count && i < categories.Length; i++)
69.         {
70.             perCategory.Add(new CategoryMetric
71.             {
72.                 Category = categories[i],
73.                 Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
74.                 Recall = 0,
75.                 F1Score = 0
76.             });
77.         }
78. 
79.         // Use confusion matrix for per-class precision/recall if available
80.         if (metrics.ConfusionMatrix.PerClassPrecision.Count > 0)
81.         {
82.             for (var i = 0; i < categories.Length && i < metrics.ConfusionMatrix.PerClassPrecision.Count; i++)
83.             {
84.                 perCategory[i].Precision = metrics.ConfusionMatrix.PerClassPrecision[i];
85.                 perCategory[i].Recall = metrics.ConfusionMatrix.PerClassRecall[i];
86.                 var p = perCategory[i].Precision;
87.                 var r = perCategory[i].Recall;
88.                 perCategory[i].F1Score = p + r > 0 ? 2 * p * r / (p + r) : 0;
89.             }
90.         }
91. 
92.         return new TrainingResult
93.         {
94.             Message = "Model trained successfully",
95.             Metrics = new EvaluationMetrics
96.             {
97.                 MacroAccuracy = metrics.MacroAccuracy,
98.                 MicroAccuracy = metrics.MicroAccuracy,
99.                 LogLoss = metrics.LogLoss,
100.                 LogLossReduction = metrics.LogLossReduction,
101.                 PerCategoryMetrics = perCategory
102.             }
103.         };
104.     }
105. 
106.     public PredictionResult Predict(TicketRequest request)
107.     {
108.         lock (_lock)
109.         {
110.             if (_predictionEngine is null)
111.                 throw new InvalidOperationException(
112.                     "Model has not been trained. Call POST /api/ticket-classifier/train first.");
113. 
114.             var input = new TicketData
115.             {
116.                 Subject = request.Subject,
117.                 Description = request.Description,
118.                 Priority = request.Priority
119.             };
120. 
121.             var prediction = _predictionEngine.Predict(input);
122. 
123.             var confidence = new Dictionary<string, float>();
124.             for (var i = 0; i < _categoryNames.Length && i < prediction.Score.Length; i++)
125.             {
126.                 confidence[_categoryNames[i]] = prediction.Score[i];
127.             }
128. 
129.             return new PredictionResult
130.             {
131.                 PredictedCategory = prediction.Category,
132.                 Confidence = confidence
133.             };
134.         }
135.     }
136. }
