             .Append(_mlContext.Transforms.Text
                 .FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
             .Append(_mlContext.Transforms.Concatenate("Features",
                 "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
             .Append(_mlContext.Transforms.Conversion
                 .MapValueToKey("Label"))
             .Append(_mlContext.MulticlassClassification.Trainers
                 .SdcaMaximumEntropy("Label", "Features"))
             .Append(_mlContext.Transforms.Conversion
                 .MapKeyToValue("PredictedLabel"));

         // Cross-validate to get metrics on the small dataset
         var cvResults = _mlContext.MulticlassClassification
             .CrossValidate(dataView, pipeline, numberOfFolds: 3);

         // Train the final model on all data
         var model = pipeline.Fit(dataView);

         lock (_lock)
         {
             _model = model;
             _categoryNames = categories;
             _predictionEngine = _mlContext.Model
                 .CreatePredictionEngine<TicketData, TicketPrediction>(model);
         }

         var best = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
         var metrics = best.Metrics;

         var perCategory = new List<CategoryMetric>();
         for (var i = 0; i < metrics.PerClassLogLoss.Count && i < categories.Length; i++)
         {
             perCategory.Add(new CategoryMetric
             {
                 Category = categories[i],
                 Precision = i < metrics.PerClassLogLoss.Count ? 1.0 - metrics.PerClassLogLoss[i] : 0,
                 Recall = 0,
                 F1Score = 0
             });
         }

         // Use confusion matrix for per-class precision/recall if available
         if (metrics.ConfusionMatrix.PerClassPrecision.Count > 0)
         {
             for (var i = 0; i < categories.Length && i < metrics.ConfusionMatrix.PerClassPrecision.Count; i++)
             {
                 perCategory[i].Precision = metrics.ConfusionMatrix.PerClassPrecision[i];
                 perCategory[i].Recall = metrics.ConfusionMatrix.PerClassRecall[i];
                 var p = perCategory[i].Precision;
                 var r = perCategory[i].Recall;
                 perCategory[i].F1Score = p + r > 0 ? 2 * p * r / (p + r) : 0;
             }
         }

         return new TrainingResult
         {
             Message = "Model trained successfully",
             Metrics = new EvaluationMetrics
             {
                 MacroAccuracy = metrics.MacroAccuracy,
                 MicroAccuracy = metrics.MicroAccuracy,
                 LogLoss = metrics.LogLoss,
                 LogLossReduction = metrics.LogLossReduction,
                 PerCategoryMetrics = perCategory
             }
         };
     }

     public PredictionResult Predict(TicketRequest request)
     {
         lock (_lock)
         {
             if (_predictionEngine is null)
                 throw new InvalidOperationException(
                     "Model has not been trained. Call POST /api/ticket-classifier/train first.");

             var input = new TicketData
             {
                 Subject = request.Subject,
                 Description = request.Description,
                 Priority = request.Priority
             };

             var prediction = _predictionEngine.Predict(input);

             var confidence = new Dictionary<string, float>();
             for (var i = 0; i < _categoryNames.Length && i < prediction.Score.Length; i++)
             {
                 confidence[_categoryNames[i]] = prediction.Score[i];
             }

             return new PredictionResult
             {
                 PredictedCategory = prediction.Category,
                 Confidence = confidence
             };
         }
     }
 }

